import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface SchedulePreview {
  time: string;
  targetTemp: number;
}

interface ThermostatData {
  currentTemperature: number;
  targetTemperature: number;
  schedulePreview: SchedulePreview[];
}

export default function Widget() {
  const thermostatData = response.data as ThermostatData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#F5F5DC' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 0.5, color: '#FF5722' }}>
              Smart Home Thermostat
            </Typography>
            <Typography variant="h4" fontWeight={500} sx={{ color: '#4A4A4A' }}>
              {thermostatData.currentTemperature}°F
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Target: {thermostatData.targetTemperature}°F
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: thermostatData.schedulePreview.map(item => item.targetTemp),
                color: '#FFC107',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: thermostatData.schedulePreview.map(item => item.time), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={1}>
            {thermostatData.schedulePreview.map((item, index) => (
              <Chip
                key={index}
                label={`${item.time}: ${item.targetTemp}°F`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFFFFF', color: '#4A4A4A' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
